/**
 * Patient compartment map — { resourceType: [linking search-param codes] }, from the CC0
 * R4 CompartmentDefinition-patient. Drives Patient/$everything (resources whose listed
 * params reference the patient). Generated by scripts/generate-compartment.ts.
 */
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";

export const patientCompartment: Record<string, string[]> = JSON.parse(
  readFileSync(fileURLToPath(new URL("./patient-compartment.json", import.meta.url)), "utf8"),
);
